        const decoded = jwt.decode(token);
        if (typeof decoded !== 'object' || !decoded.exp) {
            return true;
        }
        const now = Math.floor(Date.now() / 1000);
        const timeRemaining = decoded.exp - now;
        return timeRemaining < bufferSeconds;

