pub fn stderr_width() -> Option<usize> {
  unsafe {
    let mut winsize: libc::winsize = mem::zeroed();
    #[allow(clippy::useless_conversion)]
    if libc::ioctl(libc::STDERR_FILENO, libc::TIOCGWINSZ.into(), &mut winsize) < 0 {
      return None;
    }
    if winsize.ws_col > 0 {
      Some(winsize.ws_col as usize)
    } else {
      None
    }
  }
}

